/** 智能匹配 Tab 图标 */
export function getSmartTabIcon(name) {
    if (/势力|组织|阵营/.test(name))
        return 'fas fa-fist-raised';
    if (/技能/.test(name))
        return 'fas fa-magic';
    if (/人物|角色|npc/i.test(name))
        return 'fas fa-users';
    if (/交互|行动/.test(name))
        return 'fas fa-hand-pointer';
    if (/随机/.test(name))
        return 'fas fa-dice';
    if (/全局/.test(name))
        return 'fas fa-globe';
    if (/地点|地图/.test(name))
        return 'fas fa-map-marked-alt';
    if (/大纲/.test(name))
        return 'fas fa-book';
    return 'fas fa-table';
}
